import{_ as a,c as l,o as e,a4 as t}from"./chunks/framework.66Xi2WY6.js";const g=JSON.parse('{"title":"“好”的代码与“坏”的代码","description":"","frontmatter":{},"headers":[{"level":2,"title":"“好”的代码：","slug":"好-的代码","link":"#好-的代码","children":[]},{"level":2,"title":"“坏”的代码：","slug":"坏-的代码","link":"#坏-的代码","children":[]},{"level":2,"title":"优秀的代码是“经济”的代码","slug":"优秀的代码是-经济-的代码","link":"#优秀的代码是-经济-的代码","children":[]},{"level":2,"title":"现实环境，影响着我们对于代码“好”与“坏”的判断标准。","slug":"现实环境-影响着我们对于代码-好-与-坏-的判断标准。","link":"#现实环境-影响着我们对于代码-好-与-坏-的判断标准。","children":[{"level":3,"title":"优秀的代码需要具备三个特征： 经济、规范、安全。","slug":"优秀的代码需要具备三个特征-经济、规范、安全。","link":"#优秀的代码需要具备三个特征-经济、规范、安全。","children":[]}]}],"relativePath":"accumulation/good-bad-code.md","filePath":"accumulation/good-bad-code.md","lastUpdated":1715102671000}'),i={name:"accumulation/good-bad-code.md"},o=t('<h1 id="好-的代码与-坏-的代码" tabindex="-1">“好”的代码与“坏”的代码 <a class="header-anchor" href="#好-的代码与-坏-的代码" aria-label="Permalink to &quot;“好”的代码与“坏”的代码&quot;">​</a></h1><h2 id="好-的代码" tabindex="-1">“好”的代码： <a class="header-anchor" href="#好-的代码" aria-label="Permalink to &quot;“好”的代码：&quot;">​</a></h2><ul><li>容易理解；</li><li>没有明显的安全问题；</li><li>能够满足最关键的需求；</li><li>有充分的注释；</li><li>使用规范的命名；</li><li>经过充分的测试。</li></ul><h2 id="坏-的代码" tabindex="-1">“坏”的代码： <a class="header-anchor" href="#坏-的代码" aria-label="Permalink to &quot;“坏”的代码：&quot;">​</a></h2><ul><li>难以阅读的代码；</li><li>浪费大量计算机资源的代码；</li><li>代码风格混乱的代码；</li><li>复杂的、不直观的代码；</li><li>没有经过适当测试的代码。</li></ul><h2 id="优秀的代码是-经济-的代码" tabindex="-1">优秀的代码是“经济”的代码 <a class="header-anchor" href="#优秀的代码是-经济-的代码" aria-label="Permalink to &quot;优秀的代码是“经济”的代码&quot;">​</a></h2><p>大概也没人想记住这么多条标准吧？所以，关于优秀代码的特点，我想用“经济”这一个词语来表达。这里的“经济”，指的是使用较少的人力、物力、财力、时间、空间，来获取较大的成果或收益 。或者简单地说，<strong>投入少、收益大、投资回报高</strong>。</p><h2 id="现实环境-影响着我们对于代码-好-与-坏-的判断标准。" tabindex="-1">现实环境，影响着我们对于代码“好”与“坏”的判断标准。 <a class="header-anchor" href="#现实环境-影响着我们对于代码-好-与-坏-的判断标准。" aria-label="Permalink to &quot;现实环境，影响着我们对于代码“好”与“坏”的判断标准。&quot;">​</a></h2><p>在计算机算力不足的年代，简短的代码意味着节省昂贵的计算能力，是当时流行的编码偏好。而现在，计算能力已不再是瓶颈，如何更高效率地开发复杂的软件、编写直观的代码避免不必要的错误，成了我们首先需要考虑的问题。多核处理器出现后，代码能否充分利用多核处理器能力就成为了“好”与“坏”的判断标准。单体架构升级为微服务架构后，好的代码表现为结构优雅、分层清晰、业务边界划分明朗等。</p><p>在现代商业社会里，激烈的竞争环境迫使我们使用较少的人力、物力来获取较大的成果和收益。企业为了快速抢占市场、验证商业模式，软件开发越来越倾向于敏捷开发，提倡“快速地失败、廉价地失败”。再加上软件开发流程的差异，以及对代码质量重视程度的不同，都会影响对代码“好”与“坏”的判断标准。</p><p>所以，当我们讨论代码质量的时候，还要考虑我们所处的现实环境，超出现实环境去讨论代码的质量，有时候会有失偏颇的。最适合当前现实环境的代码，才是最优秀的代码。</p><h3 id="优秀的代码需要具备三个特征-经济、规范、安全。" tabindex="-1">优秀的代码需要具备三个特征： 经济、规范、安全。 <a class="header-anchor" href="#优秀的代码需要具备三个特征-经济、规范、安全。" aria-label="Permalink to &quot;优秀的代码需要具备三个特征： 经济、规范、安全。&quot;">​</a></h3><p><strong>关于经济：</strong></p><p>作为程序员，我们也必须考虑投入和产出。减少错误、节省时间，是我们现在选择编码方式的一个最基本的原则。</p><p><strong>关于规范：</strong></p><p>程序员间合作交流最重要的语言便是代码，规范的代码更容易被大家接受，节约测试、运营、维护阶段投入的时间。不规范的代码，在阅读、修改时会浪费我们的时间，意味着我们损失了做更有意义事情的机会。</p><p><strong>关于安全：</strong></p><p>人人都会犯错误，代码都会有 bug，但其中安全问题的破坏力有时是我们无法承受的，会对公司和个人造成不容忽视的恶劣影响，甚至造成公司破产。作为一名软件工程师，一定要重视安全问题，编写安全的代码。</p>',18),r=[o];function n(d,s,c,h,u,p){return e(),l("div",null,r)}const m=a(i,[["render",n]]);export{g as __pageData,m as default};
